-- Assign Featured to default project
SELECT p.id, c.id, 1, CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)
FROM `jr_projects` p
JOIN `jr_cats` c ON c.title = 'Featured Projects'
WHERE p.name = 'JR Programming'
ON DUPLICATE KEY UPDATE `updated_at` = VALUES(`updated_at`);

-- Assign Projects category
SELECT p.id, c.id, 1, CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)
FROM `jr_projects` p
JOIN `jr_cats` c ON c.title = 'Projects'
WHERE p.position = 'LinkedIn Project'
ON DUPLICATE KEY UPDATE `updated_at` = VALUES(`updated_at`);

-- Assign Work History category
SELECT p.id, c.id, 1, CURRENT_TIMESTAMP(3), CURRENT_TIMESTAMP(3)
FROM `jr_projects` p
JOIN `jr_cats` c ON c.title = 'Work History'
WHERE p.name LIKE '% at %'
ON DUPLICATE KEY UPDATE `updated_at` = VALUES(`updated_at`);